package com.hospital.management.model;import java.util.*;/** Header and indexed item request model; identities come from the medical record. */public class PrescriptionForm {private Long prescriptionId,medicalRecordId;private String validUntil,notes,status;private List<PrescriptionItemForm>items=new ArrayList<>();public Long getPrescriptionId(){return prescriptionId;}public void setPrescriptionId(Long v){prescriptionId=v;}public Long getMedicalRecordId(){return medicalRecordId;}public void setMedicalRecordId(Long v){medicalRecordId=v;}public String getValidUntil(){return validUntil;}public void setValidUntil(String v){validUntil=v;}public String getNotes(){return notes;}public void setNotes(String v){notes=v;}public String getStatus(){return status;}public void setStatus(String v){status=v;}public List<PrescriptionItemForm>getItems(){return items;}public void setItems(List<PrescriptionItemForm>v){items=v==null?new ArrayList<>():new ArrayList<>(v);}}
